    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0xC837A0ABC210C15BULL + 0xD78475E71E381C7FULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseA(pNonce * 0xD1856EE9D2B8EC0FULL + 0xE6804BB48EAA5CACULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseB(pNonce * 0xB63B38AF61634AB5ULL + 0xEE4DC339416B3F6DULL);
