    std::uint64_t aNonceWordM = TwistMix64::DiffuseB(pNonce * 0x9EAE8E8E03BD9F3DULL + 0xBCD89A36F6C02AF7ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseA(pNonce * 0xFD4F5FEE5CDF1397ULL + 0xB4FB2CF84682DDE0ULL);
