            //
            aOrbiterB = (aOrbiterB + aOrbiterF) + 8531394793118363836U;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterB) ^ 15352876929406908882U) ^ aOrbiterUpdateSaltA[(((31U - aIndex) + 7U)) & S_SALT1];
            aOrbiterJ = RotL64((aOrbiterJ * 475199047053777179U), 37U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterE) + 567682016232278157U;
            aOrbiterF = (aOrbiterF ^ aOrbiterI) ^ 2068146551757663119U;
            aOrbiterF = RotL64((aOrbiterF * 1557877740957797555U), 53U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterJ) + 7776122587613256525U) + aNonceWordJ;
            aOrbiterD = (aOrbiterD ^ aOrbiterH) ^ 16430938890724272256U;
            aOrbiterD = RotL64((aOrbiterD * 4540270493783593257U), 51U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterG) + 11912000645055436094U) + aNonceWordD;
            aOrbiterE = (aOrbiterE ^ aOrbiterA) ^ 16800749242578741498U;
            aOrbiterE = RotL64((aOrbiterE * 17804584625034241737U), 29U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterD) + 5909199180260499150U;
