            //
            aWandererE = aWandererE ^ (((RotL64(aScatter, 5U) + aOrbiterI) + RotL64(aOrbiterH, 37U)) + aWandererUpdateSaltD[((aIndex + 29U)) & S_SALT1]);
            aWandererB = aWandererB + (((RotL64(aPrevious, 53U) + aOrbiterH) + RotL64(aOrbiterJ, 6U)) + RotL64(aCarry, 35U));
            aWandererA = aWandererA ^ ((RotL64(aCross, 35U) + aOrbiterE) + RotL64(aOrbiterA, 47U));
